('hero', '{"name_line1":"KH. Nayeam","name_line2":"Ibna Nasir","typing_roles":["Agriculture Graduate","Full-Stack Developer","Startup Founder","Research Enthusiast"],"subtitle":"B.Sc. Agriculture graduate bridging agricultural science with full-stack development. Building scalable digital solutions that connect technical innovation with business strategy.","status_badge":"Open to Opportunities","tags":[{"icon":"MapPin","text":"Dhaka, Bangladesh"},{"icon":"GraduationCap","text":"GSTU, CGPA 3.59"},{"icon":"Briefcase","text":"CEO, Stock-X BD"}],"profile_image":"","cgpa_float":"3.59"}'::jsonb),
('about', '{"heading":"Rooted in Agriculture, Growing in Technology","subheading":"A dynamic multidisciplinary professional bridging agriculture, technology, and entrepreneurship.","career_objective":"B.Sc. Agriculture graduate and Dynamic Full-Stack Developer with a background in Finance and Startup leadership. Proven track record of building scalable digital solutions designed to bridge technical innovation with business strategy. Seeking to leverage multidisciplinary expertise and award-winning leadership to drive growth and operational efficiency in a forward-thinking organization.","career_tags":["Agriculture","Full-Stack Dev","Startup Leader","Finance"],"skills":[{"title":"Agricultural Science","desc":"Crop science, soil management & sustainable farming","icon":"Sprout"},{"title":"Full-Stack Dev","desc":"React, TypeScript, Figma, backend integration","icon":"Code","tags":["React","TypeScript","Tailwind","Figma"]},{"title":"Startup Leadership","desc":"Founded Stock-X BD, led ops & strategy","icon":"Briefcase"},{"title":"Award-Winning","desc":"VP of GSTU Central Debating Society","icon":"Trophy"}],"quick_stats":[{"icon":"Globe","label":"Languages","value":"3","sub":"BN · EN · HI"},{"icon":"FolderKanban","label":"Projects","value":"10+","sub":"Built & shipped"},{"icon":"Clock","label":"Experience","value":"3+ yrs","sub":"Tech & Agri"}]}'::jsonb),
('education', '{"items":[{"step":"01","year":"2019-2025","title":"B.Sc. (Honours) in Agriculture","subtitle":"Gopalganj Science & Technology University","badge":"CGPA 3.59 / 4.00"},{"step":"02","year":"2019","title":"HSC - Science","subtitle":"Notre Dame College, Mymensingh","badge":"GPA 4.25 / 5.00"},{"step":"03","year":"2016","title":"SSC - Science","subtitle":"Suti V.M. Pilot Model High School","badge":"GPA 5.00 / 5.00"}]}'::jsonb),
('experience', '{"main":{"name":"Stock-X BD Ltd.","role":"Founder & CEO","duration":"1 Year 8 Months","description":"Founded under UIHP at GSTU. Led product development, operations, and strategic planning for an LPG ERP platform.","tags":["LPG ERP","UI/UX Design","Frontend Dev","Team Leadership","Strategic Planning"],"url":"https://stockxbd.com"},"projects":[{"name":"Vetmedix","url":"https://vetmedixbd.com","icon":"HeartPulse","role":"Full-Stack Developer & Advisor","desc":"Full-stack pet-care platform with integrated E-commerce.","tags":["React","E-commerce","Full-Stack"]},{"name":"SLI Policy Calculator","url":"https://slipolicy.vercel.app","icon":"Globe","role":"Financial Advisor","desc":"Custom Premium Calculator to automate complex policy assessments.","tags":["Finance","Automation","Web App"]},{"name":"Coco Coffee","url":"https://coco-coffee.lovable.app","icon":"Coffee","role":"Advisor","desc":"E-commerce marketplace for health and wellness products.","tags":["E-commerce","Health","Marketplace"]}],"skill_categories":[{"category":"Development","skills":["Full-Stack Web Dev","React / TypeScript","UI/UX Design (Figma)","Frontend & Backend","ERP Development","E-commerce"]},{"category":"Agriculture","skills":["Crop Science","Soil Management","Plant Nutrition","Sustainable Farming","Agricultural Research","Organic Solutions"]},{"category":"Soft Skills","skills":["Leadership","Public Speaking","Strategic Planning","Team Coordination","MS Office (Expert)","English & Bengali"]}]}'::jsonb),
('achievements', '{"items":[{"title":"Agriculture Debating Club - Champion, Freshers Debate 3.0 & 4.0","category":"Debating","description":"Led the Agriculture Debating Club to back-to-back championship victories.","badge":"Champion","bgImage":"https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?w=600"},{"title":"1st Runner-up - Intra-University Debate, LAW Debating Club","category":"Debating","description":"Secured first runner-up position.","badge":"Runner-up","bgImage":"https://images.unsplash.com/photo-1475721027785-f74eccf877e2?w=600"},{"title":"Top 3 - UIHP Startup Founders Competition","category":"Startup","description":"Ranked in the Top 3.","badge":"Top 3","bgImage":"https://images.unsplash.com/photo-1559136555-9303baea8ebd?w=600"},{"title":"Founder & CEO - Stock-X BD Ltd.","category":"Startup","description":"Founded and led Stock-X BD Ltd.","badge":"Founder","bgImage":"https://images.unsplash.com/photo-1553877522-43269d4ea984?w=600"},{"title":"Champion - Poster on Mushroom Production Technology, IAAS 2025","category":"Scientific","description":"Won the championship in poster presentation.","badge":"Champion","bgImage":"https://images.unsplash.com/photo-1532094349884-543bc11b234d?w=600"},{"title":"Vice President - GSTU Central Debating Society","category":"Leadership","description":"Elected as Vice President.","badge":"VP","bgImage":"https://images.unsplash.com/photo-1529156069898-49953e39b3ac?w=600"},{"title":"President - Agriculture Debating Club, GSTU","category":"Leadership","description":"Served as President.","badge":"President","bgImage":"https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?w=600"}]}'::jsonb),
